impl<R: ProcessingJobProjectionRepository> ProcessingJobEventHandler for ProcessingJobProjector<R> {

    async fn on_created(&self, event: ProcessingJobCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = ProcessingJobProjection::new(
            event.id,
            event.file_id,
            event.job_type,
            event.status,
            event.priority,
            event.input_data,
            event.result_data,
            event.error_message,
            event.started_at,
            event.completed_at,
            event.retry_count,
            event.max_retries,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: ProcessingJobUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.file_id = event.file_id;
            projection.job_type = event.job_type;
            projection.status = event.status;
            projection.priority = event.priority;
            projection.input_data = event.input_data;
            projection.result_data = event.result_data;
            projection.error_message = event.error_message;
            projection.started_at = event.started_at;
            projection.completed_at = event.completed_at;
            projection.retry_count = event.retry_count;
            projection.max_retries = event.max_retries;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: ProcessingJobDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

